INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('social-worker-moex-05160', 'social-worker', 'social-worker-moex-107-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '「當案主運用平常慣用的問題解決方法已不能克服障礙，身心狀態出現失衡時，此時社會工作者 應在短期時間內，協助案主症狀減輕、強化問題解決策略和有效因應。」以上所述，是下列那個 社會個案工作實施理論（取向）的主要觀點？', '["危機介入取向", "任務中心取向", "增強權能取向", "認知行為理論"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:29+00:00", "source_pdf_sha1": "fe104a5d002b", "answer_pdf_sha1": "78b9518a750b", "source_family": "moex-gov-tw", "moex": {"exam_code": "107110", "c": "107", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "107", "exam_name": "107年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、107年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 4, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05161', 'social-worker', 'social-worker-moex-107-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '「老人送餐服務範圍大，因而距配餐地點較遠的長者常吃冷飯，但是路程遠對送餐志工也是負 荷。所幸長者附近有軍營，經過社工的努力，部隊願意認養及照顧駐區附近的老人，幫忙送餐。」 以上代表社工在執行服務計畫時，運用了下列何種策略？', '["協助志工改變服務策略", "協助案主運用內在資源", "協助案主連結潛在資源", "協助志工拓展服務網絡"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:29+00:00", "source_pdf_sha1": "fe104a5d002b", "answer_pdf_sha1": "78b9518a750b", "source_family": "moex-gov-tw", "moex": {"exam_code": "107110", "c": "107", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "107", "exam_name": "107年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、107年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 5, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05162', 'social-worker', 'social-worker-moex-107-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '「轉介」（refer）是社會個案工作的重要策略，下列敘述何者錯誤？', '["轉介基於社會工作倫理，都必須經過案主同意", "社會工作者離職、調職或方案結束，需轉換服務提供者，此種變動為轉案，而非轉介", "轉介的理由必須基於案主最佳利益，不能以轉介之名行拒絕服務狀況複雜案主之責", "同機構內不同部門或專業領域也會相互請求協助，例如：醫療人員、行政人員等會轉介案主到 社會服務部門"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:29+00:00", "source_pdf_sha1": "fe104a5d002b", "answer_pdf_sha1": "78b9518a750b", "source_family": "moex-gov-tw", "moex": {"exam_code": "107110", "c": "107", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "107", "exam_name": "107年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、107年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 6, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05163', 'social-worker', 'social-worker-moex-107-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '有關社會個案工作、心理諮商與心理治療的討論，下列何者錯誤？', '["社會工作者、諮商心理師與身心科醫師在工作場域中，會組成專業團隊，共同解決案主的問題", "社會個案工作深受精神分析學派的影響，與諮商心理師、身心科醫師一樣，都會運用特殊的方 法，以協助案主喚起潛意識，看到自己問題的本質與狀態", "當發現案主需要接受身心科治療時，需要幫助案主了解並接受此治療，在某些情況下，則需要 身心科醫師與社會工作者的聯合治療", "心理諮商解決問題，並不一定需要在社會福利機構內，才能給與服務"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:29+00:00", "source_pdf_sha1": "fe104a5d002b", "answer_pdf_sha1": "78b9518a750b", "source_family": "moex-gov-tw", "moex": {"exam_code": "107110", "c": "107", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "107", "exam_name": "107年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、107年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 7, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05164', 'social-worker', 'social-worker-moex-107-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '有關「非計畫性結案」的敘述，下列何者錯誤？', '["當社會工作者因為生病、發生意外或其他個人因素無法繼續提供服務時，機構應安排繼任的社 會工作者，並協助案主處理轉換社會工作者的情緒", "機構對於自殺或意外而失去案主的社會工作者，應注意他們的身心狀況，提供失落情緒的協助 管道", "案主發生意外或死亡，社會工作者要處理案主失去健康的失落、案主家人失去案主的失落，並 且協助案主家人轉介相關的服務資源", "對於缺席、消失、不出現的案主，社會工作者應尊重案主自我決定的權力結束服務關係"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:29+00:00", "source_pdf_sha1": "fe104a5d002b", "answer_pdf_sha1": "78b9518a750b", "source_family": "moex-gov-tw", "moex": {"exam_code": "107110", "c": "107", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "107", "exam_name": "107年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、107年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 8, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05165', 'social-worker', 'social-worker-moex-107-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '家庭內資源包括下列何者？①家庭經濟來源  ②家庭的決策者  ③家庭室內環境的安全性', '["家庭成員間的互動  ⑤家庭成員的教育程度", "", "", "⑤"]'::jsonb, 2, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:29+00:00", "source_pdf_sha1": "fe104a5d002b", "answer_pdf_sha1": "78b9518a750b", "source_family": "moex-gov-tw", "moex": {"exam_code": "107110", "c": "107", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "107", "exam_name": "107年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、107年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 9, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05166', 'social-worker', 'social-worker-moex-107-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '社會個案工作實施過程的步驟排序，下列何者正確？①開案  ②申請與接案  ③擬訂服務計畫', '["評估與結案  ⑤介入", "", "", ""]'::jsonb, 3, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:29+00:00", "source_pdf_sha1": "fe104a5d002b", "answer_pdf_sha1": "78b9518a750b", "source_family": "moex-gov-tw", "moex": {"exam_code": "107110", "c": "107", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "107", "exam_name": "107年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、107年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 10, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05167', 'social-worker', 'social-worker-moex-107-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '社會個案工作以外展方式為服務使用者提供服務與資訊，下列何者屬於外展服務？①早期療育的', '["居家服務", "辦公室會談", "經濟補助", ""]'::jsonb, 1, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:29+00:00", "source_pdf_sha1": "fe104a5d002b", "answer_pdf_sha1": "78b9518a750b", "source_family": "moex-gov-tw", "moex": {"exam_code": "107110", "c": "107", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "107", "exam_name": "107年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、107年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 11, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05168', 'social-worker', 'social-worker-moex-107-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '在社會個案工作過程中有一些執行服務計畫的介入方法是「與案主一起工作」，下列何者錯誤？', '["協助案主運用優勢特質與能力之內在資源", "透過經濟補助、醫療照顧與情緒支持協助案主處理危機", "為高齡者住屋進行無障礙改裝的物理環境改變", "運用量表以了解服務計畫的效益"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:29+00:00", "source_pdf_sha1": "fe104a5d002b", "answer_pdf_sha1": "78b9518a750b", "source_family": "moex-gov-tw", "moex": {"exam_code": "107110", "c": "107", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "107", "exam_name": "107年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、107年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 12, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05169', 'social-worker', 'social-worker-moex-107-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '有關生態圖的繪製，下列注意事項何者正確？①通常中央畫案主的家系圖  ②家系圖周圍環', '["案主/案家與系統間的關係用不同的線條表示", "線條上的箭頭代表資源的流 向是單向或雙向  ⑤案主/案家與不同系統的線條當中波折線代表不確定的關係", "", ""]'::jsonb, 2, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:29+00:00", "source_pdf_sha1": "fe104a5d002b", "answer_pdf_sha1": "78b9518a750b", "source_family": "moex-gov-tw", "moex": {"exam_code": "107110", "c": "107", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "107", "exam_name": "107年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、107年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 13, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL)
